function calendarAxisForDate(d){ return plan(d)[2]; }
function renderAnnual(){
  let y=new Date().getFullYear();
  let names=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
  annualCalendar.innerHTML=`<div class="annual-grid">`+names.map((name,m)=>{
    let first=new Date(y,m,1),last=new Date(y,m+1,0);
    let heads=['D','S','T','Q','Q','S','S'].map(x=>`<div class="head">${x}</div>`).join('');
    let cells='';
    for(let i=0;i<first.getDay();i++)cells+='<button class="mini-day empty"></button>';
    for(let day=1;day<=last.getDate();day++){
      let d=new Date(y,m,day),axis=calendarAxisForDate(d),key=iso(d),done=state.cateDone[key]?' ✅':'';
      cells+=`<button class="mini-day ${axis}" data-annual="${key}" title="${calendarReference[axis].name}">${day}${done}</button>`;
    }
    return `<div class="month-card"><h3>${name}</h3><div class="mini-grid">${heads}${cells}</div></div>`;
  }).join('')+`</div>`;
}
function bestReinforcement(){
  let pr=smartPriority();
  let low=state.grades && state.grades[pr] ? avg(state.grades[pr]) : 0;
  let ac=state.academyStats && state.academyStats[pr] ? state.academyStats[pr] : {correct:0,total:0};
  let pct=ac.total?Math.round(ac.correct/ac.total*100):0;
  return {subject:pr, avg:low, pct:pct};
}
function describeDate(key){
  let d=new Date(key+'T00:00:00'),axis=calendarAxisForDate(d),ref=calendarReference[axis],idx=saturdaysOfYear().findIndex(x=>iso(x)===key);
  let reinforcement=bestReinforcement();
  let cate = d.getDay()===6 ? `<div class="day-detail-card cate-reference"><h3>✝️ Catecismo Anual</h3><p><b>Lição ${idx+1}</b></p><p>${cateLessons[idx]?.theme||'Leitura do Catecismo'}</p><button data-open-date-cate="${key}">Abrir leitura completa</button></div>` : '';
  annualDetails.innerHTML = `
    <h2>${ref.icon} ${ref.name} — ${key}</h2>
    <p><b>Objetivo do dia:</b> ${ref.goal}</p>
    <div class="day-detail-grid">
      <div class="day-detail-card">
        <h3>📚 Disciplinas e conteúdos</h3>
        ${ref.subjects.map(s=>`<p><b>${icons[s[0]]||'📘'} ${s[0]}</b></p><ul>${s[1].map(x=>`<li>${x}</li>`).join('')}</ul>`).join('')}
      </div>
      <div class="day-detail-card">
        <h3>🏛️ Exercícios da Academia</h3>
        <ul>${ref.exercises.map(x=>`<li>${x}</li>`).join('')}</ul>
        <button data-smart-day="${ref.name}">Gerar pergunta pela prioridade</button>
      </div>
      <div class="day-detail-card reinforce">
        <h3>⭐ Reforço recomendado</h3>
        <p><b>${icons[reinforcement.subject]||'📚'} ${reinforcement.subject}</b></p>
        <p>Média no boletim: <b>${reinforcement.avg.toFixed(1)}</b></p>
        <p>Acertos na Academia: <b>${reinforcement.pct}%</b></p>
        <p>Faça perguntas extras desta disciplina até melhorar a segurança.</p>
      </div>
      ${cate}
    </div>`;
}

